import { base, commonIgnores, typescriptParsing } from "./base.mjs";

/*
 * Flat config mirroring the old `legacy-react.js` tier (ENG-1677): turbo + prettier +
 * react-hooks + the vitest convention, without the full react/typescript-eslint rule sets.
 * Used by packages (email, surveys) that predate the stricter tiers — move them to
 * `react.mjs` when they are ready.
 */
export const reactHooksConfig = [
  commonIgnores,
  typescriptParsing,
  reactHooks.configs["recommended-latest"],
  {
    languageOptions: {
      globals: {
        ...globals.browser,
      },
    },
  },
  ...base,
];

export default reactHooksConfig;

import nextConfig from "eslint-config-next";

import { base, commonIgnores, typescriptParsing } from "./base.mjs";

/*
 * Flat config for the Next.js app — the successor of `legacy-next.js` (ENG-1677):
 * eslint-config-next + turbo + prettier + the vitest convention, with the same rule
 * overrides the legacy config carried. Deliberately does not add the
 * eslint/typescript-eslint recommended baselines yet to keep rule parity with the
 * previous setup — tightening is a separate step.
 */
export const next = [
  commonIgnores,
  typescriptParsing,
  ...nextConfig,
  {
    rules: {
      "@next/next/no-html-link-for-pages": "off",
      "react/jsx-key": "off",
    },
  },
  ...base,
];

export default next;

