// ENG-1674: pin the Turbopack root to the monorepo root. Under pnpm's isolated linker,
// dependencies resolve through symlinks into <repo>/node_modules/.pnpm; without an explicit
// root, Turbopack's own root detection mis-infers the project directory and its module-graph
// import tracer panics ("there must be a path to a root").
turbopack: {
  root: fileURLToPath(new URL("../..", import.meta.url)),
},

